using Microsoft.EntityFrameworkCore;
class BlogContext : DbContext
{
    public DbSet<Blog> Blogs => Set<Blog>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        // Breaking change 1: Default discriminator property renamed from "Discriminator" to "$type".
        // Existing documents use "Discriminator", so preserve the old property name.
        modelBuilder.Entity<Blog>().HasDiscriminator<string>("Discriminator");

        // Breaking change 2: The id property value no longer includes the entity type prefix.
        // Existing documents have id in "Blog|<key>" format, so use a value converter to
        // keep reading/writing that format while the CLR Id holds only the key.
        modelBuilder.Entity<Blog>().Property(b => b.Id)
            .HasConversion(
                clr => $"Blog|{clr}",
                cosmos => cosmos.StartsWith("Blog|") ? cosmos.Substring("Blog|".Length) : cosmos);

        // Breaking change 3: HasIndex now throws for Cosmos entities (previously was silently ignored).
        // Removed: modelBuilder.Entity<Blog>().HasIndex(b => b.Name);
    }
}
class Blog { public string Id { get; set; } public string Name { get; set; } }

